const html = $input.item.json.data;
const annonces = [];

const blocs = html.split(/data-annonce="/).slice(1);

for (const bloc of blocs) {
  try {
    const jsonStringRaw = bloc.substring(0, bloc.indexOf('"'));
    const jsonString = jsonStringRaw.replace(/&quot;/g, '"');
    let dataAnnonce = {};
    try { dataAnnonce = JSON.parse(jsonString); } catch(e) {}

    const titreMatch = bloc.match(/class="h1"[^>]*>\s*([^<]+)\s*<\/span>/);
    const titre = titreMatch ? titreMatch[1].trim() : '';

    const prixMatch = bloc.match(/class="item-price[^"]*">\s*([\d\s\.]+)(?:&nbsp;)?&euro;/);
    const prix = prixMatch ? parseInt(prixMatch[1].replace(/[^\d]/g, ''), 10) : (dataAnnonce.prix || null);

    const urlMatch = bloc.match(/href="(\/annonces\/[^"]+)"/);
    const url = urlMatch ? 'https://www.pap.fr' + urlMatch[1] : '';

    const descMatch = bloc.match(/class="item-description"[^>]*>\s*([\s\S]*?)\s*<\/p>/);
    const description = descMatch ? descMatch[1].replace(/<[^>]+>/g, '').trim() : '';

    const tags = [...bloc.matchAll(/<li[^>]*>(.*?)<\/li>/g)].map(m => m[1].replace(/<[^>]+>/g, '').trim().toLowerCase());

    let surface = dataAnnonce.surface || null, pieces = null, chambres = null;
    tags.forEach(tag => {
      if (tag.includes('m²') || tag.includes('m2')) { const s = tag.match(/(\d+)/); if (s) surface = parseInt(s[1], 10); }
      if (tag.includes('pièce') || tag.includes('piece')) { const p = tag.match(/(\d+)/); if (p) pieces = parseInt(p[1], 10); }
      if (tag.includes('chambre')) { const c = tag.match(/(\d+)/); if (c) chambres = parseInt(c[1], 10); }
    });

    let dpe = null;
    const dpeMatch = bloc.match(/dpe[-_ ]?([a-gA-G])\b/i);
    if (dpeMatch) dpe = dpeMatch[1].toUpperCase();

    // Filtre : on exige titre + (prix ou description) pour qu'un bien soit utile
    if ((dataAnnonce.id || url) && titre && (prix || description)) {
      annonces.push({ json: {
        id: dataAnnonce.id || null, prix, localisation: titre, url,
        surface_m2: surface, nb_pieces: pieces, nb_chambres: chambres,
        dpe, description, tags_bruts: tags, source: 'PAP',
        date_scraping: new Date().toISOString()
      }});
    }
  } catch(e) { continue; }
}

return annonces;

const items = $input.all();

return items.map(item => {
  const data = item.json;

  const contexteAnnonce = [
    '<annonce>',
    'Localisation : ' + (data.localisation || 'Non précisé'),
    'Prix : ' + (data.prix ? data.prix + ' €' : 'Non précisé'),
    'Surface : ' + (data.surface_m2 ? data.surface_m2 + ' m²' : 'Non précisée'),
    'Pièces : ' + (data.nb_pieces || 'Non précisé'),
    'Chambres : ' + (data.nb_chambres || 'Non précisé'),
    'DPE : ' + (data.dpe || 'Non précisé'),
    'Tags : ' + (data.tags_bruts && data.tags_bruts.length > 0 ? data.tags_bruts.join(', ') : 'Aucun'),
    'Description : ' + (data.description || 'Aucune description'),
    '</annonce>'
  ].join('\n');

  const userContent = [
    'Analyse cette annonce immobilière pour préparer un mail de prospection.',
    '',
    contexteAnnonce,
    '',
    'Ta mission :',
    '1. Évaluer le potentiel du bien (Fort, Moyen, Faible).',
    "2. Identifier le nombre d'étages (déduis-le de la description ou des tags).",
    '3. Rédiger un email de prise de contact percutant et naturel.',
    '4. Note sur 100 le bien en fonction de sa pertinence et justifie en détail ton jugement.',
    "5. Trouver l'argument d'accroche principal.",
    '',
    'Réponds STRICTEMENT au format JSON valide, sans texte ni balises markdown :',
    '{"score": <entier 0-100>, "analyse": "justification", "script": "Bonjour...", "accroche": "argument principal", "etage": "nombre ou Non précisé", "potentiel": "fort, moyen ou faible", "type": "appartement ou maison"}'
  ].join('\n');

  return { json: {
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 1000,
      system: 'Tu es un expert immobilier redoutable, spécialisé dans la prospection mail (pige immobilière).',
      messages: [{ role: 'user', content: userContent }]
    }),
    id: data.id, prix: data.prix, localisation: data.localisation, url: data.url,
    surface_m2: data.surface_m2, nb_pieces: data.nb_pieces, nb_chambres: data.nb_chambres,
    dpe: data.dpe, description: data.description, tags_bruts: data.tags_bruts,
    source: data.source, date_scraping: data.date_scraping
  } };
});

const claudeResponse = $input.first().json;
// .item (pas .first()) pour avoir le bon item original selon l'index courant
const original = $('Mise en forme pour IA').item.json;

const formatFrDate = (dateStr) => {
  if (!dateStr) return 'Date inconnue';
  try {
    return new Intl.DateTimeFormat('fr-FR', {
      day: '2-digit', month: '2-digit', year: 'numeric',
      hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris'
    }).format(new Date(dateStr)).replace(',', ' -');
  } catch(e) { return dateStr; }
};

const rawContent = claudeResponse.content?.[0]?.text || '';
let parsed = { score: 0, analyse: 'Erreur parsing', script: '', accroche: '', potentiel: 'Inconnu', type: '', etage: 'Non précisé' };
try {
  const m = rawContent.match(/\{[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
} catch(e) {}

return [{ json: {
  ...original,
  date:      formatFrDate(original.date_scraping),
  score:     parsed.score     || 0,
  analyse:   parsed.analyse   || '',
  script:    parsed.script    || '',
  accroche:  parsed.accroche  || '',
  potentiel: parsed.potentiel || 'Non détecté',
  type:      parsed.type      || '',
  emoji:     (parsed.type || '').toLowerCase().includes('maison') ? '🏠' : '🏢',
  etage:     parsed.etage     || 'Non précisé'
} }];

const allItems = $input.first().json.items || [];
const cfg = $('⚙️ Configuration').first().json;

const scoreColor = (s) => s >= 70 ? '#1A7A4A' : s >= 40 ? '#E07B00' : '#c84040';
const potIcon    = (p) => (p || '').toLowerCase() === 'fort' ? '🔥' : (p || '').toLowerCase() === 'moyen' ? '🌤️' : '❄️';

const lignes = allItems.map(d => [
  '<div style="background:white;border:1px solid #e0e0e0;margin:10px 0;border-radius:6px;overflow:hidden;">',
  '<div style="background:#EDF5FF;padding:12px 14px;border-left:4px solid #2E5FAC;display:flex;justify-content:space-between;align-items:center;">',
  '<b style="color:#1B3A6B;font-size:14px;">' + (d.localisation || 'Localisation inconnue') + '</b>',
  '<span style="background:' + scoreColor(d.score) + ';color:white;padding:2px 10px;border-radius:12px;font-size:12px;">' + (d.score || 0) + '/100</span>',
  '</div>',
  '<div style="padding:10px 14px;">',
  '<div style="color:#555;font-size:13px;margin-bottom:6px;">' +
    (d.prix ? '💰 <b>' + Number(d.prix).toLocaleString('fr-FR') + ' €</b>' : '') +
    (d.potentiel ? ' &nbsp;·&nbsp; ' + potIcon(d.potentiel) + ' Potentiel ' + d.potentiel : '') +
  '</div>',
  d.accroche ? '<div style="font-size:12px;color:#444;font-style:italic;margin-bottom:8px;">"' + d.accroche + '"</div>' : '',
  d.url ? '<a href="' + d.url + '" style="background:#2E5FAC;color:white;padding:5px 12px;border-radius:4px;text-decoration:none;font-size:12px;font-weight:bold;">Voir l\'annonce →</a>' : '',
  '</div></div>'
].join('')).join('');

const html = [
  '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f6fa;">',
  '<div style="background:#1B3A6B;padding:24px;border-radius:8px 8px 0 0;">',
  '<h2 style="color:white;margin:0;font-size:20px;">📋 Pige du ' + new Date().toLocaleDateString('fr-FR') + '</h2>',
  '<p style="color:#a8c4e8;margin:8px 0 0;font-size:13px;">' + allItems.length + ' annonces analysées par IA · Scripts et analyses dans LeadFlow</p>',
  '</div>',
  '<div style="padding:0 12px 12px;">' + lignes + '</div>',
  '<div style="background:#1B3A6B;padding:14px;border-radius:0 0 8px 8px;text-align:center;">',
  '<a href="' + cfg.LEADFLOW_URL + '/pige" style="color:white;font-size:13px;text-decoration:none;font-weight:bold;">Consulter l\'analyse complète dans LeadFlow →</a>',
  '</div></div>'
].join('');

return [{ json: {
  html,
  subject: '📋 Pige du ' + new Date().toLocaleDateString('fr-FR') + ' — ' + allItems.length + ' nouvelles annonces'
} }];
